B.Pv={"Perder peso":0,"Ganar m\xfasculo":1,"Mejorar resistencia":2,"Reducir estr\xe9s":3,"Mejorar autoestima":4}
B.MD=s(["P\xe1rate con los pies juntos y los brazos a los lados.","Salta abriendo piernas al ancho de los hombros mientras subes los brazos.","Vuelve a la posici\xf3n inicial saltando de nuevo.","Aterriza suave con las rodillas levemente flexionadas.","Mant\xe9n el ritmo constante durante toda la serie."],t.s)
B.LU=s(["Quema calor\xedas r\xe1pidamente.","Mejora la coordinaci\xf3n y el equilibrio.","Activa todo el cuerpo en un solo movimiento.","No requiere equipamiento ni espacio grande."],t.s)
B.Hl=new A.cw("Saltos de tijera","https://okdiario.com/metabolic/wp-content/uploads/2024/09/Saltos-de-tijera-5-pasos-para-hacer-este-ejercicio-para-perder-peso-a-tu-rutina-de-fitness.jpg",3,30,"Piernas, gl\xfateos, hombros, cardio",B.MD,B.LU,"Respira de forma constante, no aguantes el aire.")
B.JX=s([u.m,"Mant\xe9n la espalda recta y el pecho hacia arriba.","Baja como si fueras a sentarte en una silla.","Las rodillas no deben pasar la punta de los pies.","Sube empujando desde los talones."],t.s)
B.MY=s(["Fortalece los m\xfasculos m\xe1s grandes del cuerpo.","Activa el metabolismo y quema grasa.","Mejora la postura y la estabilidad.","Funcional para actividades del d\xeda a d\xeda."],t.s)
B.Hy=new A.cw("Sentadillas","https://image.tuasaude.com/media/article/3k/ru/6-exercicios-de-agachamento-para-gluteos_9131.jpg",4,45,"Cu\xe1driceps, gl\xfateos, isquiotibiales, core",B.JX,B.MY,"Mant\xe9n los talones apoyados en el suelo todo el tiempo.")
B.Nf=s(["P\xe1rate derecho con los pies juntos.","Baja las manos al suelo y lleva los pies atr\xe1s en posici\xf3n de plancha.","Haz una flexi\xf3n (opcional para principiantes).","Lleva los pies hacia las manos de un salto.","Salta hacia arriba con los brazos extendidos."],t.s)
B.KM=s(["Es uno de los ejercicios m\xe1s completos que existen.","Quema muchas calor\xedas en poco tiempo.","Mejora la fuerza y la resistencia simult\xe1neamente.","Acelera el metabolismo incluso despu\xe9s de entrenar."],t.s)
B.Hx=new A.cw("Burpees","https://www.shutterstock.com/image-photo/movement-sequence-latin-sporty-woman-600nw-2204166209.jpg",3,60,"Cuerpo completo: pecho, core, piernas, cardio",B.Nf,B.KM,"Empieza lento y ve aumentando el ritmo con las series.")
B.KR=s(["Col\xf3cate en posici\xf3n de plancha alta con los brazos extendidos.","Mant\xe9n las caderas bajas, alineadas con el cuerpo.","Lleva una rodilla al pecho r\xe1pidamente.","Vuelve y alterna con la otra pierna.","Mant\xe9n el core activado durante todo el movimiento."],t.s)
B.Lz=s(["Trabaja el abdomen de forma intensa.","Mejora la coordinaci\xf3n y velocidad.","Eleva la frecuencia card\xedaca r\xe1pidamente.","Fortalece los hombros y la parte alta del cuerpo."],t.s)
B.Hk=new A.cw("Escaladores","https://images.unsplash.com/photo-1635031520206-2bbe2dfa4d68?q=80&w=2070&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D",3,30,"Core, hombros, caderas, cardio",B.KR,B.Lz,"Las caderas no deben subir ni bajar, mant\xe9n la plancha firme.")
B.La=s(["Apoya los antebrazos y las puntas de los pies en el suelo.","El cuerpo debe formar una l\xednea recta de cabeza a talones.","Activa el abdomen como si fueras a recibir un golpe.","Mira hacia el suelo para mantener el cuello neutro.","Mant\xe9n la posici\xf3n el tiempo indicado sin perder la forma."],t.s)
B.MZ=s(["Fortalece el core de forma isom\xe9trica y segura.","Mejora la postura y reduce el dolor de espalda.","Estabiliza la columna vertebral.","Activa m\xfaltiples grupos musculares al mismo tiempo."],t.s)
B.Hw=new A.cw("Plancha abdominal",u.X,3,30,"Core completo, hombros, gl\xfateos",B.La,B.MZ,"Respira de forma continua, no aguantes el aire.")
B.ML=s([B.Hl,B.Hy,B.Hx,B.Hk,B.Hw],t.Fe)
B.Mg=s(["Col\xf3cate boca abajo con las manos al ancho de los hombros.","El cuerpo debe estar recto de cabeza a talones.","Baja el pecho hasta casi tocar el suelo.","Mant\xe9n los codos a 45 grados del cuerpo.",u.I],t.s)
B.Na=s(["Desarrolla el pectoral sin necesidad de pesas.","Fortalece tr\xedceps y hombros simult\xe1neamente.","Mejora la estabilidad del core.","Ejercicio funcional que imita movimientos reales."],t.s)
B.Hr=new A.cw("Flexiones de pecho",u.x,4,60,"Pectoral, tr\xedceps, hombros anteriores",B.Mg,B.Na,"No dejes caer las caderas ni subas los gl\xfateos.")
B.L1=s(["Pies ligeramente m\xe1s anchos que los hombros, puntillas hacia afuera.","Baja lentamente hasta que los muslos queden paralelos o m\xe1s abajo.","Mant\xe9n el pecho arriba y la espalda recta.","Empuja desde los talones para subir.","Extiende completamente las rodillas al llegar arriba."],t.s)
B.Lj=s(["Activa m\xe1s fibras musculares que la sentadilla normal.","Desarrolla gl\xfateos y cu\xe1driceps intensamente.","Mejora la movilidad de cadera y tobillos.","Base de casi todos los movimientos funcionales."],t.s)
B.Hv=new A.cw("Sentadilla profunda","https://www.trakphysio.com/wp-content/uploads/sites/612/2023/05/15-14.jpg",4,90,"Cu\xe1driceps, gl\xfateos, isquiotibiales, pantorrillas",B.L1,B.Lj,"Si los talones se levantan, trabaja la movilidad de tobillo.")
B.Lc=s(["P\xe1rate derecho con los pies juntos.","Da un paso largo hacia adelante con una pierna.","Baja la rodilla trasera casi hasta tocar el suelo.","El torso debe mantenerse erguido durante todo el movimiento.","Empuja con el pie delantero y alterna la pierna."],t.s)
B.Ld=s(["Trabaja cada pierna de forma independiente.","Mejora el equilibrio y la coordinaci\xf3n.","Corrige desbalances musculares entre piernas.","Activa los gl\xfateos en todo el rango de movimiento."],t.s)
B.HF=new A.cw("Zancadas alternas","https://hips.hearstapps.com/hmg-prod/images/alternate-lunges-1586168385.jpg?resize=980:*",3,60,"Cu\xe1driceps, gl\xfateos, isquiotibiales, equilibrio",B.Lc,B.Ld,"La rodilla delantera no debe pasar la punta del pie.")
B.Ls=s(["Col\xf3cate en posici\xf3n de flexi\xf3n est\xe1ndar.","Junta las manos bajo el pecho formando un diamante con los dedos.","Baja el pecho hacia las manos controladamente.","Mant\xe9n los codos pegados al cuerpo al bajar.","Empuja hasta extender los brazos completamente."],t.s)
B.LI=s(["A\xedsla el tr\xedceps mejor que cualquier flexi\xf3n normal.","Desarrolla la parte interna del pectoral.","Mejora la definici\xf3n de los brazos.","No necesita equipamiento."],t.s)
B.Hq=new A.cw("Flexiones diamante","https://i.ytimg.com/vi/jaxbEHLC4qU/maxresdefault.jpg",3,75,"Tr\xedceps, pectoral interno, hombros",B.Ls,B.LI,"Es m\xe1s dif\xedcil que la flexi\xf3n normal, empieza despacio.")
B.Ne=s(["Si\xe9ntate en el borde de una silla o superficie estable.","Pon las manos en el borde con los dedos hacia adelante.","Desliza el cuerpo fuera de la silla y baja doblando los codos.","Baja hasta que los codos formen 90 grados.",u.I],t.s)
B.LV=s(["Trabaja el tr\xedceps de forma efectiva sin pesas.","F\xe1cil de hacer en casa con cualquier silla.","Mejora la fuerza de empuje de los brazos.","Complementa perfectamente las flexiones."],t.s)
B.Hu=new A.cw("Fondos de tr\xedceps en silla","https://hips.hearstapps.com/hmg-prod/images/cajo-n-1621951089.jpeg",3,60,"Tr\xedceps, hombros, pectoral inferior",B.Ne,B.LV,"Codos hacia atr\xe1s, no hacia los lados.")
B.KX=s([B.Hr,B.Hv,B.HF,B.Hq,B.Hu],t.Fe)
B.N3=s(["P\xe1rate con los pies juntos.","Empieza a trotar levantando las rodillas al menos a la cadera.","Mueve los brazos de forma natural como al correr.","Mant\xe9n el torso ligeramente inclinado hacia adelante.","Aterriza suavemente en la punta de los pies."],t.s)
B.KK=s(["Mejora la resistencia cardiovascular.","Se puede hacer en cualquier espacio peque\xf1o.","Calienta todo el cuerpo r\xe1pidamente.","Fortalece los m\xfasculos de las piernas."],t.s)
B.HD=new A.cw("Trote en el lugar",u.l,5,20,"Piernas, cardio, coordinaci\xf3n",B.N3,B.KK,"Mant\xe9n un ritmo constante durante el minuto completo.")
B.MR=s([u.m,"Baja en sentadilla hasta que los muslos queden paralelos.","Explota hacia arriba saltando lo m\xe1s alto posible.","Extiende los brazos hacia arriba al saltar.","Aterriza suave y baja de nuevo directamente a la sentadilla."],t.s)
B.Lo=s(["Combina fuerza y cardio en un solo movimiento.","Quema muchas calor\xedas en poco tiempo.","Mejora la potencia explosiva de las piernas.","Acelera el metabolismo."],t.s)
B.Hs=new A.cw("Sentadillas + salto","https://images.unsplash.com/photo-1599058945522-28d584b6f0ff?w=800&q=80",4,45,"Cu\xe1driceps, gl\xfateos, pantorrillas, cardio",B.MR,B.Lo,"Aterriza con las rodillas flexionadas para proteger las articulaciones.")
B.Kb=s(["Posici\xf3n de plancha alta con brazos extendidos.","Alterna las rodillas hacia el pecho lo m\xe1s r\xe1pido posible.","Mant\xe9n las caderas bajas y el core activado.","Respira de forma constante durante el ejercicio.","No pierdas la posici\xf3n de plancha por la velocidad."],t.s)
B.M1=s(["Eleva la frecuencia card\xedaca muy r\xe1pido.","Trabaja el core de forma din\xe1mica.","Mejora la coordinaci\xf3n y velocidad.","Quema grasa eficientemente."],t.s)
B.Hn=new A.cw("Escaladores r\xe1pidos","https://images.unsplash.com/photo-1549060279-7e168fcee0c2?w=800&q=80",4,20,"Core, hombros, caderas, cardio",B.Kb,B.M1,"La velocidad no vale si pierdes la forma correcta.")
B.LT=s(["Haz una flexi\xf3n completa.","Al subir, lleva la rodilla derecha hacia el pecho.","Vuelve a posici\xf3n de plancha.","Haz otra flexi\xf3n y lleva la rodilla izquierda.","Alterna el movimiento de rodilla en cada repetici\xf3n."],t.s)
B.LO=s(["Combina fuerza de tren superior con movilidad de cadera.","Activa el core en cada repetici\xf3n.","Mejora la coordinaci\xf3n entre tren superior e inferior.","Mayor gasto cal\xf3rico que una flexi\xf3n normal."],t.s)
B.HE=new A.cw("Flexiones + rodilla al pecho",u.x,3,40,"Pectoral, tr\xedceps, core, caderas",B.LT,B.LO,"Controla la respiraci\xf3n: exhala al subir.")
B.K2=s(["10 sentadillas sin parar.","Inmediatamente 10 flexiones.","Inmediatamente 10 saltos de tijera.","Eso cuenta como 1 ronda completa.","Descansa solo entre rondas."],t.s)
B.MX=s(["Entrena fuerza y resistencia simult\xe1neamente.","Simula el entrenamiento en circuito de gym.","Maximiza el gasto cal\xf3rico.","Mejora la capacidad de recuperaci\xf3n."],t.s)
B.Hp=new A.cw("Circuito sin pausa","https://images.unsplash.com/photo-1601422407692-ec4eeec1d9b3?w=800&q=80",3,60,"Cuerpo completo",B.K2,B.MX,"El reto es no parar dentro de la ronda.")
B.Lu=s([B.HD,B.Hs,B.Hn,B.HE,B.Hp],t.Fe)
B.N9=s(["Si\xe9ntate c\xf3modamente con la espalda recta.","Coloca una mano en el abdomen.","Inhala por la nariz contando 4 segundos.","Ret\xe9n el aire contando 7 segundos.","Exhala lentamente por la boca contando 8 segundos."],t.s)
B.MK=s(["Activa el sistema nervioso parasimp\xe1tico.","Reduce la ansiedad en minutos.","Mejora la concentraci\xf3n y el enfoque.","Ayuda a conciliar el sue\xf1o."],t.s)
B.HC=new A.cw("Respiraci\xf3n 4-7-8",u.a,3,30,"Sistema nervioso, diafragma",B.N9,B.MK,"El abdomen debe expandirse al inhalar, no el pecho.")
B.N8=s(["Arrod\xedllate en el suelo con los gl\xfateos sobre los talones.","Inclina el torso hacia adelante extendiendo los brazos.","Apoya la frente en el suelo o en una almohada.","Respira profundamente sintiendo el estiramiento en la espalda.","Mant\xe9n la postura el tiempo indicado sin tensi\xf3n."],t.s)
B.Lg=s(["Alivia la tensi\xf3n en la espalda baja.","Estira caderas, muslos y tobillos.","Calma la mente y reduce el estr\xe9s.","Ideal para hacer antes de dormir."],t.s)
B.Hz=new A.cw("Postura del ni\xf1o","https://images.unsplash.com/photo-1544367567-0f2fcb009e0b?w=800&q=80",3,20,"Espalda baja, caderas, hombros",B.N8,B.Lg,"No fuerces nada, deja que la gravedad haga el trabajo.")
B.K8=s(["Si\xe9ntate o p\xe1rate con la espalda recta.","Inclina lentamente la cabeza hacia la derecha.","Mant\xe9n 20 segundos sintiendo el estiramiento.","Vuelve al centro lentamente.","Repite hacia el lado izquierdo."],t.s)
B.K4=s(["Libera la tensi\xf3n acumulada por el estr\xe9s.","Reduce los dolores de cabeza tensionales.","Mejora la movilidad del cuello.","Se puede hacer en cualquier momento del d\xeda."],t.s)
B.Ho=new A.cw("Estiramiento de cuello",u.X,3,15,"Cuello, trapecios, hombros",B.K8,B.K4,"Nunca hagas rotaciones r\xe1pidas o forzadas de cuello.")
B.LP=s(["Sal a caminar sin tel\xe9fono o con \xe9l en el bolsillo.","Observa conscientemente lo que te rodea.","Siente cada paso: el suelo, el movimiento, el aire.","Respira profundo al ritmo de tus pasos.","Si la mente divaga, vuelve la atenci\xf3n al caminar."],t.s)
B.L5=s(["Reduce el cortisol (hormona del estr\xe9s).","Mejora el estado de \xe1nimo r\xe1pidamente.","Practica el mindfulness de forma natural.","Activa el cuerpo sin generar m\xe1s estr\xe9s."],t.s)
B.Hj=new A.cw("Caminata consciente",u.l,1,0,"Mente, piernas, respiraci\xf3n",B.LP,B.L5,"No se trata de llegar a ning\xfan lado, solo de estar presente.")
B.N7=s(["P\xe1rate o si\xe9ntate con la espalda recta.","Sube los hombros hacia las orejas.","Lleva los hombros hacia atr\xe1s en un c\xedrculo amplio.","B\xe1jalos y tr\xe1elos hacia adelante cerrando el c\xedrculo.","Haz 10 rotaciones hacia atr\xe1s y 10 hacia adelante."],t.s)
B.MP=s(["Libera la tensi\xf3n de hombros y cuello.","Mejora la circulaci\xf3n en la zona alta de la espalda.","Previene contracturas por mala postura.","Ideal para hacer despu\xe9s de estar sentado mucho tiempo."],t.s)
B.HB=new A.cw("Rotaci\xf3n de hombros",u.a,3,20,"Hombros, trapecios, cuello",B.N7,B.MP,"Haz los c\xedrculos lo m\xe1s amplios posible.")
B.LH=s([B.HC,B.Hz,B.Ho,B.Hj,B.HB],t.Fe)
B.Ku=s(["P\xe1rate con los pies separados al ancho de los hombros.","Pon las manos en la cadera o extiende los brazos en V.","Saca el pecho, levanta el ment\xf3n y mira al frente.","Respira profundo y mant\xe9n la posici\xf3n 2 minutos.","Piensa en algo que hayas logrado mientras la mantienes."],t.s)
B.Lv=s(["Reduce el cortisol y aumenta la testosterona.","Mejora la confianza antes de situaciones importantes.","Cambia el estado mental en minutos.","Practicada por atletas y l\xedderes de alto rendimiento."],t.s)
B.Hm=new A.cw("Postura de poder",u.a,3,30,"Mente, postura, confianza",B.Ku,B.Lv,"Dos minutos son suficientes para sentir el efecto.")
B.Mk=s([u.m,'Al bajar en sentadilla di mentalmente: "soy capaz".','Al subir di mentalmente: "lo estoy logrando".',"Mant\xe9n el pecho arriba y la mirada al frente.","Cada repetici\xf3n es un recordatorio de tu fortaleza."],t.s)
B.Lk=s(["Combina ejercicio f\xedsico con programaci\xf3n mental positiva.","Refuerza la conexi\xf3n mente-cuerpo.","Mejora la autoestima con cada repetici\xf3n.","Transforma el ejercicio en un acto de amor propio."],t.s)
B.Hi=new A.cw("Sentadillas con afirmaci\xf3n","https://images.unsplash.com/photo-1574680178050-55c6a6a96e0a?w=800&q=80",3,45,"Cu\xe1driceps, gl\xfateos, mente positiva",B.Mk,B.Lk,"No importa cu\xe1ntas hagas, importa c\xf3mo te sientes al hacerlas.")
B.Ma=s(["Posici\xf3n de flexi\xf3n con el cuerpo recto.","Baja lentamente contando 3 segundos.","Sube en 1 segundo de forma explosiva.","Celebra mentalmente cada repetici\xf3n completada.","Observa tu esfuerzo y recon\xf3celo."],t.s)
B.M8=s(["La lentitud aumenta la tensi\xf3n muscular y los resultados.","Cada rep completada refuerza la sensaci\xf3n de logro.","Mejora la conexi\xf3n entre mente y m\xfasculo.","Construye disciplina y constancia."],t.s)
B.Ht=new A.cw("Flexiones lentas y conscientes",u.x,3,60,"Pectoral, tr\xedceps, hombros, autoconfianza",B.Ma,B.M8,"Menos repeticiones bien hechas valen m\xe1s que muchas mal.")
B.K9=s(["Pon tu canci\xf3n favorita.","Mu\xe9vete como quieras, sin reglas ni coreograf\xeda.","Ocupa todo el espacio disponible.","Cierra los ojos si te ayuda a soltarte.","Disfruta el movimiento sin juzgarte."],t.s)
B.Lq=s(["Libera endorfinas y mejora el estado de \xe1nimo.","Reduce la verg\xfcenza y el miedo al juicio.","Expresi\xf3n corporal que conecta con las emociones.","Quema calor\xedas sin que parezca ejercicio."],t.s)
B.Hh=new A.cw("Baile libre","https://images.unsplash.com/photo-1547153760-18fc86324498?w=800&q=80",3,0,"Cuerpo completo, estado de \xe1nimo",B.K9,B.Lq,"No hay forma incorrecta de bailar cuando nadie te ve.")
B.Le=s(["Sal a caminar por tu espacio o por la calle.","Hombros hacia atr\xe1s y abajo, pecho abierto.","Mirada al frente, no al suelo.","Camina como si fueras a algo importante.","Mant\xe9n el ritmo constante y la postura durante todo el recorrido."],t.s)
B.K0=s(["Cambia el lenguaje corporal y la percepci\xf3n de uno mismo.","Mejora la postura a largo plazo.","Genera una sensaci\xf3n de prop\xf3sito y direcci\xf3n.","Combina actividad f\xedsica con trabajo mental."],t.s)
B.HA=new A.cw("Caminata con cabeza en alto",u.l,1,0,"Postura, confianza, piernas",B.Le,B.K0,"La forma en que te mueves cambia c\xf3mo te sientes.")
B.Kr=s([B.Hm,B.Hi,B.Ht,B.Hh,B.HA],t.Fe)
